//! BIDS layout and query implementation
//!
//! This module provides functionality for parsing BIDS entities
//! and querying templates based on BIDS conventions.

use crate::error::{Result, TemplateFlowError};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::{Path, PathBuf};

/// BIDS entities that can be present in a filename
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum BidsEntity {
    Template,
    Resolution,
    Density,
    Atlas,
    Suffix,
    Description,
    Extension,
    Label,
    Segmentation,
    Hemisphere,
    Space,
}

impl BidsEntity {
    /// Get the short form used in filenames (e.g., "res" for Resolution)
    pub fn key(&self) -> &'static str {
        match self {
            BidsEntity::Template => "tpl",
            BidsEntity::Resolution => "res",
            BidsEntity::Density => "den",
            BidsEntity::Atlas => "atlas",
            BidsEntity::Suffix => "suffix",
            BidsEntity::Description => "desc",
            BidsEntity::Extension => "ext",
            BidsEntity::Label => "label",
            BidsEntity::Segmentation => "seg",
            BidsEntity::Hemisphere => "hemi",
            BidsEntity::Space => "space",
        }
    }

    /// Parse from a key string
    pub fn from_key(key: &str) -> Option<Self> {
        match key {
            "tpl" => Some(BidsEntity::Template),
            "res" => Some(BidsEntity::Resolution),
            "den" => Some(BidsEntity::Density),
            "atlas" => Some(BidsEntity::Atlas),
            "suffix" => Some(BidsEntity::Suffix),
            "desc" => Some(BidsEntity::Description),
            "ext" => Some(BidsEntity::Extension),
            "label" => Some(BidsEntity::Label),
            "seg" => Some(BidsEntity::Segmentation),
            "hemi" => Some(BidsEntity::Hemisphere),
            "space" => Some(BidsEntity::Space),
            _ => None,
        }
    }
}

/// A single file in the template layout
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TemplateFile {
    /// Full path to the file
    pub path: PathBuf,
    /// Template name
    pub template: String,
    /// BIDS entities extracted from the filename
    pub entities: HashMap<String, String>,
    /// File suffix (e.g., "T1w", "mask", "dseg")
    pub suffix: Option<String>,
    /// File extension (e.g., "nii.gz", "json", "tsv")
    pub extension: Option<String>,
}

impl TemplateFile {
    /// Create a new TemplateFile by parsing a path
    pub fn from_path(path: &Path) -> Result<Self> {
        let filename = path
            .file_name()
            .and_then(|n| n.to_str())
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Invalid filename".to_string()))?;

        let entities = parse_entities(filename)?;

        let template = entities
            .get("tpl")
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Missing template entity".to_string()))?
            .clone();

        let suffix = extract_suffix(filename);
        let extension = extract_extension(filename);

        Ok(TemplateFile {
            path: path.to_path_buf(),
            template,
            entities,
            suffix,
            extension,
        })
    }

    /// Check if this file matches the given query parameters
    pub fn matches(&self, query: &HashMap<String, String>) -> bool {
        for (key, value) in query {
            match key.as_str() {
                "suffix" => {
                    if self.suffix.as_ref() != Some(value) {
                        return false;
                    }
                }
                "extension" => {
                    if self.extension.as_ref() != Some(value) {
                        return false;
                    }
                }
                _ => {
                    if self.entities.get(key) != Some(value) {
                        return false;
                    }
                }
            }
        }
        true
    }
}

/// Parse BIDS entities from a filename
fn parse_entities(filename: &str) -> Result<HashMap<String, String>> {
    let mut entities = HashMap::new();

    // Remove extension(s) to get the base name
    let base = filename.split('.').next().unwrap_or(filename);

    // Split by underscore to get entity pairs
    let parts: Vec<&str> = base.split('_').collect();

    for part in parts {
        if let Some(dash_pos) = part.find('-') {
            let key = &part[..dash_pos];
            let value = &part[dash_pos + 1..];

            // Validate that this is a known entity
            if BidsEntity::from_key(key).is_some() {
                entities.insert(key.to_string(), value.to_string());
            }
        }
    }

    Ok(entities)
}

/// Extract the suffix from a filename (last part after underscore, before extension)
fn extract_suffix(filename: &str) -> Option<String> {
    // Remove extensions
    let base = filename.split('.').next()?;

    // Get the last part after underscore
    let parts: Vec<&str> = base.split('_').collect();
    let last_part = parts.last()?;

    // If it doesn't contain a dash, it's likely a suffix
    if !last_part.contains('-') {
        Some(last_part.to_string())
    } else {
        None
    }
}

/// Extract the extension(s) from a filename (e.g., "nii.gz", "json")
fn extract_extension(filename: &str) -> Option<String> {
    if let Some(dot_pos) = filename.find('.') {
        Some(filename[dot_pos + 1..].to_string())
    } else {
        None
    }
}

/// Template layout containing all files for available templates
#[derive(Debug, Default, Serialize, Deserialize)]
pub struct TemplateLayout {
    /// Map from template name to list of files
    pub templates: HashMap<String, Vec<TemplateFile>>,
}

impl TemplateLayout {
    /// Create a new empty layout
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a file to the layout
    pub fn add_file(&mut self, file: TemplateFile) {
        self.templates
            .entry(file.template.clone())
            .or_insert_with(Vec::new)
            .push(file);
    }

    /// Get all templates
    pub fn get_templates(&self) -> Vec<&str> {
        self.templates.keys().map(|s| s.as_str()).collect()
    }

    /// Get files for a specific template
    pub fn get_template_files(&self, template: &str) -> Option<&[TemplateFile]> {
        self.templates.get(template).map(|v| v.as_slice())
    }

    /// Query files across all templates
    pub fn query(&self, query: &HashMap<String, String>) -> Vec<&TemplateFile> {
        let mut results = Vec::new();

        // If template is specified in query, only search that template
        if let Some(template) = query.get("tpl") {
            if let Some(files) = self.templates.get(template) {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        } else {
            // Search all templates
            for files in self.templates.values() {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        }

        results
    }
}

