fn test_skeleton_parsing_integration() {
    let skel_path = std::path::Path::new("../../python-client/templateflow/conf/templateflow-skel.zip");

    if !skel_path.exists() {
        eprintln!("Skipping test: skeleton file not found");
        return;
    }

    let layout = load_skeleton_from_file(skel_path).expect("Failed to load skeleton");

    // Verify we have multiple templates
    let templates = layout.get_templates();
    assert!(templates.len() > 10, "Expected more than 10 templates");

    // Check some known templates exist
    let expected_templates = ["MNI152Lin", "MNI152NLin2009cAsym", "fsaverage", "OASIS30ANTs"];
    for template in &expected_templates {
        assert!(
            templates.contains(&template),
            "Expected template {} not found",
            template
        );
    }

    // Test specific template files
    let mni_files = layout.get_template_files("MNI152Lin").expect("MNI152Lin not found");
    assert!(!mni_files.is_empty(), "MNI152Lin should have files");

    // Test querying for T1w files
    let query = HashMap::from([
        ("tpl".to_string(), "MNI152Lin".to_string()),
        ("suffix".to_string(), "T1w".to_string()),
    ]);
    let results = layout.query(&query);
    assert!(!results.is_empty(), "Should find T1w files for MNI152Lin");

    // Verify file properties
    for file in results {
        assert_eq!(file.template, "MNI152Lin");
        assert_eq!(file.suffix, Some("T1w".to_string()));
        assert!(file.extension.is_some());
    }

    // Test resolution queries
    let res_query = HashMap::from([
        ("tpl".to_string(), "MNI152Lin".to_string()),
        ("res".to_string(), "01".to_string()),
    ]);
    let res_results = layout.query(&res_query);
    assert!(!res_results.is_empty(), "Should find resolution 01 files");

    // Test atlas queries
    let atlas_query = HashMap::from([
        ("tpl".to_string(), "MNI152NLin2009cAsym".to_string()),
        ("atlas".to_string(), "DiFuMo".to_string()),
    ]);
    let atlas_results = layout.query(&atlas_query);
    if !atlas_results.is_empty() {
        for file in atlas_results {
            assert!(file.entities.get("atlas").map(|v| v == "DiFuMo").unwrap_or(false));
        }
    }
}

#[test]
fn test_bids_entity_parsing() {
    // Test various filename patterns
    let test_cases = vec![
        (
            "tpl-MNI152Lin_res-01_T1w.nii.gz",
